#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
const int N=1<<10|10;int n,a[N][N];
typedef pair<int,int> pii;vector<pii> ans;
inline void dfs(int n)
{
//	printf("cnm :: %d\n",n);
	if(n==3)
	{
		ans.push_back({2,3});
		ans.push_back({3,1});
		ans.push_back({2,2});
		ans.push_back({1,1});
		ans.push_back({3,3});
		ans.push_back({3,2}); 
		ans.push_back({1,2});
		ans.push_back({1,3});
		ans.push_back({2,1});
		return;
	}
	if(n==4)
	{
		ans.push_back({1,2});
		ans.push_back({4,3});
		ans.push_back({2,1});
		ans.push_back({3,4});
		ans.push_back({1,3});
		ans.push_back({4,2});
		ans.push_back({3,1});
		ans.push_back({2,4});
		ans.push_back({2,2});
		ans.push_back({1,4});
		ans.push_back({2,3});
		ans.push_back({3,3});
		ans.push_back({4,1});
		ans.push_back({4,4});
		return;
	}
//	printf("cnm :: %d\n",n);
	ans.push_back({n,n});
	ans.push_back({n-1,n-2});
	ans.push_back({n,n-1});
	ans.push_back({n-2,n-1});
	ans.push_back({n-1,n-1});
	ans.push_back({n,n-2});
	ans.push_back({n-2,n});
	ans.push_back({n-1,n});
	bool f=0;
	drep(n-3,1,i)
	{
		if(!f)
		{
			ans.push_back({n-1,i});
			ans.push_back({n,i});
			ans.push_back({i,n});
			ans.push_back({i,n-1});
		}
		else
		{
			ans.push_back({n,i});
			ans.push_back({n-1,i});
			ans.push_back({i,n-1});
			ans.push_back({i,n});
		}
		f^=1;
	}

	return dfs(n-2);
}
int main()
{
	scanf("%d",&n);
	if(n==1){printf("1\n1 1\n");return 0;}
	if(n==2){printf("1\n1 1\n");return 0;}
	dfs(n);
	printf("%d\n",int(ans.size()));int cnt=0;
	for(pii v:ans)printf("%d %d\n",v.first,v.second),a[v.first][v.second]=++cnt;
//	puts("<<<");
//	rep(1,n,i){rep(1,n,j)printf("%d ",a[i][j]);puts("");}
}
